import React from "react";
import Sidebar from "../../components/Sidebar";
import { Outlet } from "react-router-dom";

const DashboardLayout = () => {
  return (
    <div className="flex">

      {/* Sidebar */}
      <Sidebar />

      {/* Main Content */}
      <div
        className="ml-64 w-full min-h-screen bg-cover bg-center p-10"
        style={{
          backgroundImage:
            "url(https://images.unsplash.com/photo-1556742049-0cfed4f6a45d)"
        }}
      >

        <div className="bg-black/40 backdrop-blur-lg p-8 rounded-xl min-h-screen">

          <Outlet />

        </div>

      </div>

    </div>
  );
};

export default DashboardLayout;
